public object FfiConverterTypeRovenueCore: FfiConverter<RovenueCore, Pointer> {
    override fun lower(value: RovenueCore): Pointer = value.callWithPointer { it }

    override fun lift(value: Pointer): RovenueCore {
        return RovenueCore(value)
    }

    override fun read(buf: ByteBuffer): RovenueCore {
        // The Rust code always writes pointers as 8 bytes, and will
        // fail to compile if they don't fit.
        return lift(Pointer(buf.getLong()))
    }

    override fun allocationSize(value: RovenueCore) = 8

    override fun write(value: RovenueCore, buf: ByteBuffer) {
        // The Rust code always expects pointers written as 8 bytes,
        // and will fail to compile if they don't fit.
        buf.putLong(Pointer.nativeValue(lower(value)))
    }
}




