sealed class RovenueException(message: String): Exception(message) {
        // Each variant is a nested class
        // Flat enums carries a string error message, so no special implementation is necessary.
        class NotConfigured(message: String) : RovenueException(message)
        class InvalidApiKey(message: String) : RovenueException(message)
        class InvalidArgument(message: String) : RovenueException(message)
        class ServerException(message: String) : RovenueException(message)
        class NetworkUnavailable(message: String) : RovenueException(message)
        class Timeout(message: String) : RovenueException(message)
        class RateLimited(message: String) : RovenueException(message)
        class Storage(message: String) : RovenueException(message)
        class UserNotFound(message: String) : RovenueException(message)
        class InsufficientCredits(message: String) : RovenueException(message)
        class EntitlementInactive(message: String) : RovenueException(message)
        class DuplicatePurchase(message: String) : RovenueException(message)
        class ReceiptInvalid(message: String) : RovenueException(message)
        class Internal(message: String) : RovenueException(message)
        

    companion object ErrorHandler : CallStatusErrorHandler<RovenueException> {
        override fun lift(error_buf: RustBuffer.ByValue): RovenueException = FfiConverterTypeRovenueError.lift(error_buf)
    }
}

public object FfiConverterTypeRovenueError : FfiConverterRustBuffer<RovenueException> {
    override fun read(buf: ByteBuffer): RovenueException {
        
            return when(buf.getInt()) {
            1 -> RovenueException.NotConfigured(FfiConverterString.read(buf))
            2 -> RovenueException.InvalidApiKey(FfiConverterString.read(buf))
            3 -> RovenueException.InvalidArgument(FfiConverterString.read(buf))
            4 -> RovenueException.ServerException(FfiConverterString.read(buf))
            5 -> RovenueException.NetworkUnavailable(FfiConverterString.read(buf))
            6 -> RovenueException.Timeout(FfiConverterString.read(buf))
            7 -> RovenueException.RateLimited(FfiConverterString.read(buf))
            8 -> RovenueException.Storage(FfiConverterString.read(buf))
            9 -> RovenueException.UserNotFound(FfiConverterString.read(buf))
            10 -> RovenueException.InsufficientCredits(FfiConverterString.read(buf))
            11 -> RovenueException.EntitlementInactive(FfiConverterString.read(buf))
            12 -> RovenueException.DuplicatePurchase(FfiConverterString.read(buf))
            13 -> RovenueException.ReceiptInvalid(FfiConverterString.read(buf))
            14 -> RovenueException.Internal(FfiConverterString.read(buf))
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
        
    }

    override fun allocationSize(value: RovenueException): Int {
        return 4
    }

    override fun write(value: RovenueException, buf: ByteBuffer) {
        when(value) {
            is RovenueException.NotConfigured -> {
                buf.putInt(1)
                Unit
            }
            is RovenueException.InvalidApiKey -> {
                buf.putInt(2)
                Unit
            }
            is RovenueException.InvalidArgument -> {
                buf.putInt(3)
                Unit
            }
            is RovenueException.ServerException -> {
                buf.putInt(4)
                Unit
            }
            is RovenueException.NetworkUnavailable -> {
                buf.putInt(5)
                Unit
            }
            is RovenueException.Timeout -> {
                buf.putInt(6)
                Unit
            }
            is RovenueException.RateLimited -> {
                buf.putInt(7)
                Unit
            }
            is RovenueException.Storage -> {
                buf.putInt(8)
                Unit
            }
            is RovenueException.UserNotFound -> {
                buf.putInt(9)
                Unit
            }
            is RovenueException.InsufficientCredits -> {
                buf.putInt(10)
                Unit
            }
            is RovenueException.EntitlementInactive -> {
                buf.putInt(11)
                Unit
            }
            is RovenueException.DuplicatePurchase -> {
                buf.putInt(12)
                Unit
            }
            is RovenueException.ReceiptInvalid -> {
                buf.putInt(13)
                Unit
            }
            is RovenueException.Internal -> {
                buf.putInt(14)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




